mapper.select:
SELECT TC.COMPANY_ID, TC.COMPANY_NM, TC.COMPANY_TYPE, TC.CEO_NM, TC.USE_YN, TO_CHAR(TC.REG_DT, 'YYYYMMDD') AS REG_DT, TC.BRANCH_ID FROM TM_COMPANY TC WHERE 1=1
AND TC.COMPANY_ID = #{COMPANY_ID}
AND TC.COMPANY_NM LIKE '%' || #{COMPANY_NM} || '%'
AND TC.COMPANY_TYPE = #{COMPANY_TYPE}
AND TC.USE_YN = #{USE_YN}
ORDER BY TC.COMPANY_ID

SELECT ND.DELIVERY_ID, ND.DELIVERY_NM, ND.COMPANY_ID, TC.COMPANY_NM, ND.TEL_NO, ND.USE_YN FROM TM_NUMPLATE_DELIVERY ND, TM_COMPANY TC WHERE ND.COMPANY_ID = TC.COMPANY_ID(+)
AND ND.COMPANY_ID = #{COMPANY_ID}
ORDER BY ND.DELIVERY_ID
